sql:
SELECT COUNT(DISTINCT user_id) AS follower_count
FROM follows
WHERE status = 'active';

SELECT route_id
FROM routes
WHERE date = (SELECT MIN(date) FROM routes);

SELECT route_type
FROM routes
WHERE route_id = 1;

SELECT users.user_name, achievements.achievement_name
FROM users
INNER JOIN achievements ON users.user_id = achievements.user_id;

SELECT routes.route_color, routes.route_grade, routes.route_type, routes.style, routes.difficulty_level, routes.description, users.user_name, users.role
FROM routes
INNER JOIN users ON routes.creator_id = users.user_id;

SELECT DISTINCT route_color
FROM routes
WHERE route_type = 'Flash';

SELECT user_name 
FROM users 
WHERE user_id NOT IN (SELECT user_id FROM comments);

external_knowledge:
- 'hues' refers to 'route_color';
- 'levels of difficulty' corresponds to 'route_grade';
- 'paths that serve as the foundation for beginners' ascending journeys' means routes with 'Top Rope' type, which are typically easier routes for beginners;
- 'climbing steepness from gentle to vertiginous' refers to sorting by route_grade in ascending order.

- In this context, "travelers" refers to the users;
- "Journey paths" refer to the routes;
- "Captain of the voyage" refers to the user who created the route;
- "Sailor" is a metaphorical term for a user.

sql:
SELECT routes.route_id, routes.route_grade, walls.wall_name
FROM routes
JOIN walls ON routes.wall_id = walls.wall_id;

external_knowledge:
- 'dazzling paths' refers to routes with high ratings;
- 'vibrant hues and noble grades' represent the route color and route grade;
- 'majestic walls' refers to walls where the routes are located;
- 'intricate grades' and 'bold styles' refer to the grade description and style description, respectively;
- 'highly praised in the climbing community' means the rating of the route is greater than 4.
